import anthropic

client = anthropic.Anthropic()

REACT_SYSTEM = """
You are a research assistant that solves tasks step by step.

Before each action, write a thought block in this format:

Thought: <current understanding> | <what is still needed> | <chosen tool and why>

Then call the appropriate tool.

When you have enough information to answer fully, write:
Final Answer: <your complete answer>

Never skip the Thought step. Never guess — if you need data, fetch it.
"""

TOOLS = [
    {
        "name": "search",
        "description": "Search the web for current information.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search query"},
            },
            "required": ["query"],
        },
    },
    {
        "name": "calculate",
        "description": "Evaluate a mathematical expression and return the result.",
        "input_schema": {
            "type": "object",
            "properties": {
                "expression": {"type": "string", "description": "Python arithmetic expression, e.g. '2 ** 10'"},
            },
            "required": ["expression"],
        },
    },
]

import json

def search(query: str) -> str:
    return json.dumps({"results": [
        {"title": "Paris population 2024", "snippet": "Paris has ~2.1M residents in the city proper."},
    ]})

def calculate(expression: str) -> str:
    try:
        return str(eval(expression, {"__builtins__": {}}, {}))
    except Exception as exc:
        return f"Error: {exc}"

DISPATCH = {"search": search, "calculate": calculate}

messages = [{"role": "user", "content": "What is twice the population of Paris in thousands?"}]

for _ in range(10):
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=REACT_SYSTEM,
        tools=TOOLS,
        messages=messages,
    )
    messages.append({"role": "assistant", "content": resp.content})

    tool_calls = [b for b in resp.content if b.type == "tool_use"]
    if not tool_calls:
        for block in resp.content:
            if block.type == "text":
                print(block.text)
        break

    results = []
    for block in tool_calls:
        result = DISPATCH[block.name](**block.input)
        results.append({
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": result,
        })
    messages.append({"role": "user", "content": results})

# The message history now contains interleaved Thought/tool-call/tool-result traces,
# making the agent's reasoning fully auditable.

# Extracting thoughts and final answer from the message history

def extract_thoughts_and_answer(messages: list[dict]) -> dict:
    """
    Parse the message history for Thought blocks and the Final Answer.
    Returns a dict with all thoughts and the final answer text.
    """
    thoughts = []
    final_answer = None

    for msg in messages:
        if msg["role"] != "assistant":
            continue
        for block in (msg["content"] if isinstance(msg["content"], list) else []):
            if not hasattr(block, "text"):
                continue
            text = block.text
            for line in text.splitlines():
                if line.startswith("Thought:"):
                    thoughts.append(line[len("Thought:"):].strip())
                elif line.startswith("Final Answer:"):
                    final_answer = line[len("Final Answer:"):].strip()

    return {"thoughts": thoughts, "final_answer": final_answer}

