import anthropic
import json

client = anthropic.Anthropic()

UNCERTAINTY_SYSTEM = """
You are a customer service agent.

Before each action, write a Thought. When you are uncertain, say so explicitly:

Thought: I know X. I am uncertain about Y because Z.
  Confidence: HIGH | MEDIUM | LOW
  If LOW: I will fetch more evidence before acting.
  If MEDIUM: I will proceed with [interpretation] and note the uncertainty in my answer.
  If HIGH: I will proceed directly.

Next: <tool>(<args>)
"""

TOOLS = [
    {
        "name": "get_order",
        "description": "Get order details by order ID.",
        "input_schema": {
            "type": "object",
            "properties": {"order_id": {"type": "string"}},
            "required": ["order_id"],
        },
    },
]

def get_order(order_id: str) -> str:
    orders = {
        "1042": {"status": "shipped", "eta": "2024-06-15"},
        "1043": {"status": "pending"},
    }
    return json.dumps(orders.get(order_id, {"error": "not found"}))

messages = [
    {"role": "user", "content": "I think my order number is 1042 or maybe 1043. When will it arrive?"},
]

for _ in range(8):
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=UNCERTAINTY_SYSTEM,
        tools=TOOLS,
        messages=messages,
    )
    messages.append({"role": "assistant", "content": resp.content})

    tool_calls = [b for b in resp.content if b.type == "tool_use"]
    if not tool_calls:
        for block in resp.content:
            if block.type == "text":
                print(block.text)
        break

    results = []
    for block in tool_calls:
        result = get_order(**block.input)
        results.append({
            "type": "tool_result",
            "tool_use_id": block.id,
            "content": result,
        })
    messages.append({"role": "user", "content": results})

