import json
from datetime import datetime

def extract_reasoning_trace(messages: list[dict]) -> list[dict]:
    """
    Extract a structured log of each reasoning step from the message history.
    Returns a list of {step, thought, tools_called, timestamp}.
    """
    trace = []
    step = 0
    ts = datetime.utcnow().isoformat()

    for msg in messages:
        if msg["role"] != "assistant":
            continue
        content = msg["content"]
        if not isinstance(content, list):
            continue

        thought_text = None
        tools_called = []

        for block in content:
            if hasattr(block, "text"):
                for line in block.text.splitlines():
                    if line.startswith("Thought:"):
                        thought_text = line[len("Thought:"):].strip()
            elif hasattr(block, "name"):
                tools_called.append({
                    "tool": block.name,
                    "input": block.input,
                })

        if thought_text or tools_called:
            step += 1
            trace.append({
                "step": step,
                "thought": thought_text,
                "tools_called": tools_called,
                "timestamp": ts,
            })

    return trace

